{"code": "import json

# Load NASDAQ Capital Market stocks
with open('file_storage/functions.query_db:32.json', 'r') as f:
    nasdaq_stocks = json.load(f)

# Create company name mapping (cleaner names)
company_map = {}
for stock in nasdaq_stocks:
    symbol = stock['Symbol']
    desc = stock['Company Description']
    # Clean up company name for better display
    if '. ' in desc:
        name = desc.split('. ')[0]
    elif ' specializes' in desc:
        name = desc.split(' specializes')[0]
    elif ' focuses' in desc:
        name = desc.split(' focuses')[0]
    elif ' is ' in desc:
        name = desc.split(' is ')[0]
    else:
        name = desc
    company_map[symbol] = name

# Get all symbols
symbols = list(company_map.keys())
print(f'Analyzing {len(symbols)} NASDAQ Capital Market stocks...')

# Since we can't process all at once efficiently, let's create a structured approach
stock_list = []
for symbol in symbols:
    stock_list.append({
        'symbol': symbol,
        'company': company_map[symbol]
    })

result = {
    'stocks': stock_list,
    'count': len(stock_list)
}

print('__RESULT__:')
print(json.dumps(result))"}

